PROCEDURE MEMORY_READ(address)
BEGIN
    // Place address on address bus
    ADDRESS_BUS ← address

    // Assert memory read control signal
    CONTROL_BUS.MEMORY_READ ← TRUE
    CONTROL_BUS.WRITE ← FALSE

    // Wait for memory response (with wait states)
    WHILE NOT CONTROL_BUS.READY DO
        // Insert wait states
        CLOCK_CYCLE ← CLOCK_CYCLE + 1
    END WHILE

    // Read data from data bus
    DATA ← DATA_BUS

    // Deassert control signals
    CONTROL_BUS.MEMORY_READ ← FALSE

    RETURN DATA
END

#include <stdio.h>
#include <stdbool.h>

#define NUM_DEVICES 4

// Device priority (lower number = higher priority)
int device_priority[NUM_DEVICES] = {0, 1, 2, 3};
bool bus_request[NUM_DEVICES] = {false, false, false, false};
bool bus_grant[NUM_DEVICES] = {false, false, false, false};
bool bus_busy = false;

// Function to request the bus
void request_bus(int device_id) {
    if (device_id >= 0 && device_id < NUM_DEVICES) {
        bus_request[device_id] = true;
        printf("Device %d requested the bus\n", device_id);
    }
}

// Function to release the bus
void release_bus(int device_id) {
    if (device_id >= 0 && device_id < NUM_DEVICES) {
        bus_request[device_id] = false;
        bus_grant[device_id] = false;
        bus_busy = false;
        printf("Device %d released the bus\n", device_id);
    }
}

// Arbitration function - grants bus to highest priority requester
void arbitration() {
    if (bus_busy) return;

    for (int priority = 0; priority < NUM_DEVICES; priority++) {
        for (int device = 0; device < NUM_DEVICES; device++) {
            if (device_priority[device] == priority && bus_request[device]) {
                bus_grant[device] = true;
                bus_busy = true;
                printf("Bus granted to Device %d (priority %d)\n", device, priority);
                return;
            }
        }
    }
}

int main() {
    // Simulate arbitration scenario
    request_bus(1);
    request_bus(3);
    arbitration();

    release_bus(1);
    return 0;
}
